class RedisSessionInterface:
    def __init__(self, redis_client, prefix='session:'):
        self.redis = redis_client
        self.prefix = prefix

    def generate_session_id(self):
        import uuid
        return str(uuid.uuid4())

    def get_session(self, session_id):
        if not session_id:
            return {}
        key = f"{self.prefix}{session_id}"
        data = self.redis.get(key)
        if data:
            return pickle.loads(data)
        return {}

    def set_session(self, session_id, data, expiry=3600):
        key = f"{self.prefix}{session_id}"
        self.redis.setex(key, expiry, pickle.dumps(data))

    def delete_session(self, session_id):
        key = f"{self.prefix}{session_id}"
        self.redis.delete(key)


session_interface = RedisSessionInterface(redis_client)


def cache_query(expiry=300, key_prefix='cache:query:'):
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            cache_key_data = {
                'func': func.__name__,
                'args': args,
                'kwargs': kwargs
            }
            cache_key_str = json.dumps(cache_key_data, sort_keys=True)
            cache_key_hash = hashlib.md5(cache_key_str.encode()).hexdigest()
            cache_key = f"{key_prefix}{cache_key_hash}"
            
            cached_result = redis_client.get(cache_key)
            if cached_result:
                return pickle.loads(cached_result)
            
            result = func(*args, **kwargs)
            redis_client.setex(cache_key, expiry, pickle.dumps(result))
            
            return result
        return wrapper
    return decorator


def invalidate_cache(key_pattern='cache:query:*'):
    keys = redis_client.keys(key_pattern)
    if keys:
        redis_client.delete(*keys)


