@app.before_request
def load_session():
    session_id = request.cookies.get('session_id')
    request.session_data = session_interface.get_session(session_id)
    request.session_id = session_id


@app.after_request
def save_session(response):
    if hasattr(request, 'session_data') and hasattr(request, 'session_modified'):
        if request.session_modified:
            if not request.session_id:
                request.session_id = session_interface.generate_session_id()
            session_interface.set_session(request.session_id, request.session_data, expiry=3600)
            response.set_cookie('session_id', request.session_id, max_age=3600, httponly=True)
    return response


def get_session_value(key, default=None):
    return request.session_data.get(key, default)


def set_session_value(key, value):
    request.session_data[key] = value
    request.session_modified = True


def delete_session_value(key):
    if key in request.session_data:
        del request.session_data[key]
        request.session_modified = True


@app.route('/login', methods=['POST'])
def login():
    data = request.get_json()
    username = data.get('username')
    user_id = data.get('user_id', 1)
    
    set_session_value('username', username)
    set_session_value('user_id', user_id)
    set_session_value('logged_in', True)
    
    return jsonify({
        'status': 'success',
        'message': 'Logged in successfully',
        'session_id': request.session_id
    })


